import{_ as s}from"./plugin-vue_export-helper-c27b6911.js";import{r as a,o as e,c as l,b as r,d as n,e as t,f as g}from"./app-c4b3e62b.js";const h="/website_assets/components/mq/queue.png",d="/website_assets/components/mq/publisher.png",c="/website_assets/components/mq/rabbitMQ.png",i="/website_assets/components/mq/pd_demo.png",p="/website_assets/components/mq/dis_trans.png",u="/website_assets/components/mq/psc.png",b={},m=g('<h2 id="mq使用场景" tabindex="-1"><a class="header-anchor" href="#mq使用场景" aria-hidden="true">#</a> MQ使用场景</h2><ol><li>异步处理</li><li>流量控制</li><li>服务解耦</li></ol><p><strong>MQ缺点</strong>:</p><ol><li>增加延迟</li><li>增加系统复杂度</li><li>可能产生数据不一致问题</li></ol><h2 id="mq主流产品" tabindex="-1"><a class="header-anchor" href="#mq主流产品" aria-hidden="true">#</a> MQ主流产品</h2><h3 id="第一梯队" tabindex="-1"><a class="header-anchor" href="#第一梯队" aria-hidden="true">#</a> 第一梯队</h3><ol><li><strong>RabbitMQ</strong><ol><li><strong>优点</strong><ol><li><strong>开箱即用(轻量级)</strong></li><li>Exchange模块(交换机)，支持路由配置</li><li>客户端支持最多的编程语言</li><li>支持AMQP协议</li></ol></li><li><strong>缺点</strong><ol><li>对消息积压支持不好，大量消息积压时性能急剧下降</li><li><strong>性能最差(几万～十几万/秒)</strong></li><li>开发语言Erlang学习曲线陡峭</li></ol></li></ol></li><li><strong>RocketMQ</strong><ol><li><strong>优点</strong>： <ol><li>性能(几十万/秒)、稳定性和可靠性都不错</li><li>响应时延低(低延迟)</li><li>金融级稳定性</li><li>适合 <strong>在线业务</strong></li></ol></li><li><strong>缺点</strong>： <ol><li><strong>周边生态系统相对较差</strong></li></ol></li></ol></li><li><strong>Kafka</strong><ol><li><strong>优点</strong>： <ol><li><strong>周边生态系统兼容性最好</strong>！</li><li><strong>异步收发性能最好(吞吐量高)</strong>！</li><li>适合<strong>日志、监控、大数据、流计算</strong></li></ol></li><li><strong>缺点</strong>： <ol><li><strong>同步响应时延较高</strong>(攒一波再发送/处理)</li><li><strong>不太适合在线业务</strong></li></ol></li></ol></li></ol><h3 id="第二梯队" tabindex="-1"><a class="header-anchor" href="#第二梯队" aria-hidden="true">#</a> 第二梯队</h3><ol><li><strong>ActiveMQ</strong><br> 最老牌消息队列，仅用于兼容旧系统</li><li><strong>ZeroMQ</strong><br> 更适合称为“基于消息队列的多线程网络库”</li><li><strong>Pulsar</strong><br> 特点: 存储 &amp; 计算分离</li></ol><h2 id="消息模型" tabindex="-1"><a class="header-anchor" href="#消息模型" aria-hidden="true">#</a> 消息模型</h2><h3 id="队列模型" tabindex="-1"><a class="header-anchor" href="#队列模型" aria-hidden="true">#</a> 队列模型</h3><p>任何一条消息只能被其中的一个消费者收到<br><img src="'+h+'" alt="队列模型" loading="lazy"></p><h3 id="发布-订阅模型-publish-subscribe-pattern" tabindex="-1"><a class="header-anchor" href="#发布-订阅模型-publish-subscribe-pattern" aria-hidden="true">#</a> 发布-订阅模型(Publish-Subscribe Pattern)</h3><p>与队列模型<strong>最大区别</strong>：一份消息数据能不能被消费多次的问题<br><img src="'+d+'" alt="发布-订阅模型" loading="lazy"></p><h2 id="rabbitmq消息模型" tabindex="-1"><a class="header-anchor" href="#rabbitmq消息模型" aria-hidden="true">#</a> RabbitMQ消息模型</h2><p>使用 <strong>队列模型</strong>，通过 <strong>Exchange模块</strong> 实现发布-订阅模型功能。</p><details><summary> See Detail </summary> 使用 队列模型，通过 Exchange模块 实现 “发布-订阅模型” 中 “一份数据可被多个订阅者消费的的功能”。 <p>Exchange模块决定将消息投递到哪个队列中，若同一份消息有多个消费者，则Exchange模块会将消息发送至多个队列。</p></details><figure><img src="'+c+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><h2 id="rocketmq-kafka消息模型" tabindex="-1"><a class="header-anchor" href="#rocketmq-kafka消息模型" aria-hidden="true">#</a> RocketMQ/Kafka消息模型</h2><p>使用 <strong>发布-订阅模型</strong><br><img src="'+i+'" alt="" loading="lazy"></p><p>每个 <strong>主题(Topic)</strong> 包含多个<strong>队列(Queue)/分区(Partition)</strong>，通过多个队列来实现多实例并行生产和消费。</p><p>消息有序性：只能保证 <strong>队列层面</strong> 的消息有序性，主题层面<strong>无法保证</strong>消息严格有序。</p><p>消息可靠性：<strong>“请求-确认”机制</strong>。</p><p><strong>生产</strong> 和 <strong>消费</strong> 过程中，分别有1次请求-确认机制。</p><h2 id="消息队列基本概念" tabindex="-1"><a class="header-anchor" href="#消息队列基本概念" aria-hidden="true">#</a> 消息队列基本概念</h2><figure><img src="'+i+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><ul><li><strong>生产者(Producer): 发布者(Publisher)</strong></li><li><strong>消费组(Consumer Group): 订阅者(Subscriber)</strong><ol><li>每个 <strong>消费组(Consumer Group)</strong> 都消费 <strong>主题(Topic)</strong> 中一份完整的消息(所有队列的全部消息)，不同消费组之间消费进度不受影响</li><li>一个消费组中包含多个 <strong>消费者(Consumer)实例</strong>，同一组内的消费者是竞争消费关系</li><li>同一消费组在每个队列上只能串行消费，多个队列加在一起就是并行消费，<strong>并行度</strong>就是队列数量</li><li>某个队列在同一消费组中最多只能由一个消费者实例占用</li><li>接4，<strong>分区 → 消费者: 1 : 1，消费者 → 分区: 1 : N</strong></li><li>Consumer Group 对应 Topic，Consumer对应Queue</li></ol></li><li><strong>消费者(Consumer):</strong> 消费组下的消费实例</li><li><strong>消费位置(Consumer Offset)</strong>: 记录消费组在当前队列的消费位置 <ol><li>每个消费组在每个队列上维护一个消费位置(<strong>注</strong>: 消费位置和消费者无关)</li><li>消费位置一般保存在Broker中(RocketMQ/Kafka)</li></ol></li><li><strong>主题(Topic):</strong> 服务端存放消息的容器</li><li><strong>队列(Queue)/分区(Partition):</strong> 一个主题包含多个队列/分区，通过队列/分区实现多实例并行生产和消费</li><li><strong>服务端(Broker):</strong> 存储队列的服务器</li></ul><h2 id="分布式事务" tabindex="-1"><a class="header-anchor" href="#分布式事务" aria-hidden="true">#</a> 分布式事务</h2><p>常见分布式事务实现</p><ol><li>两阶段提交-2PC(Two-phase Commit)</li><li>TCC(Try-Confirm-Cancel)</li><li>事务消息</li></ol><p>消息队列通过 <strong>事务消息</strong> 实现分布式事务。</p><p><img src="'+p+'" alt="" loading="lazy"><br><strong>步骤4</strong> 提交/回滚失败处理方案</p><ol><li>Kafka会直接抛出异常，用户自行解决，重试 or 其他。</li><li>RocketMQ增加 <strong>事务反查机制</strong> 解决(业务代码提供反查接口)。</li></ol><h2 id="消息丢失-重复-积压" tabindex="-1"><a class="header-anchor" href="#消息丢失-重复-积压" aria-hidden="true">#</a> <strong>消息丢失 &amp; 重复 &amp; 积压</strong></h2><h3 id="消息丢失处理-消息可靠性传递" tabindex="-1"><a class="header-anchor" href="#消息丢失处理-消息可靠性传递" aria-hidden="true">#</a> <strong>消息丢失处理(消息可靠性传递)</strong></h3><h4 id="检测消息丢失的方法" tabindex="-1"><a class="header-anchor" href="#检测消息丢失的方法" aria-hidden="true">#</a> <strong>检测消息丢失的方法</strong></h4><p>利用消息队列的 <strong>有序性</strong> 验证是否有消息丢失(使用 <strong>拦截器机制</strong>)</p><p><strong>注</strong>：</p><ol><li>多实例Producer，则每个Producer生成各自消息序号(带Producer标识)</li><li>需指定队列/分区(Partition)，每个分区单独检测</li><li>Consumer端按Producer检测序号连续性，Consumer实例数要与分区数量一致</li></ol><h4 id="消息生产-消费流程" tabindex="-1"><a class="header-anchor" href="#消息生产-消费流程" aria-hidden="true">#</a> <strong>消息生产-消费流程</strong></h4><figure><img src="'+u+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><ul><li><strong>生产阶段</strong><br> 编写发送消息代码时，正确处理返回值或捕捉异常，即可保证消息不丢失</li><li><strong>存储阶段</strong><br> 将消息写入磁盘后，再给Producer返回确认响应<br> 多Broker节点集群，则需至少将消息发送到2个以上节点，再给Producer返回响应</li><li><strong>消费阶段</strong><br> 执行完消费逻辑后，再返回消费确认响应</li></ul><h2 id="重复消息处理" tabindex="-1"><a class="header-anchor" href="#重复消息处理" aria-hidden="true">#</a> <strong>重复消息处理</strong></h2><p><strong>消息重复不可避免</strong>, 服务质量标准：</p><ol><li><strong>At most once</strong>：至多一次(消息最多送达一次)，没有消息可靠性保证，允许丢消息</li><li><strong>At least once</strong>：至少一次，不允许丢失消息，但允许少量重复消息出现</li><li><strong>Exactly once</strong>：恰好一次，只会被送达一次，不允许丢失 &amp; 重复</li></ol><h3 id="使用幂等性解决重复消息问题" tabindex="-1"><a class="header-anchor" href="#使用幂等性解决重复消息问题" aria-hidden="true">#</a> <strong>使用幂等性解决重复消息问题</strong></h3><p><strong>At least once + 幂等消费 = Exactly once</strong></p><h3 id="幂等消费实现方式" tabindex="-1"><a class="header-anchor" href="#幂等消费实现方式" aria-hidden="true">#</a> <strong>幂等消费实现方式</strong></h3><p>从消费业务逻辑设计入手，将 <strong>消费业务逻辑</strong> 设计成具备幂等性的操作，包括</p><ol><li>设置数据库唯一约束(<strong>unique key</strong>)</li><li>为更新的数据设置前置条件(增加 <strong>版本号属性</strong>)</li><li>记录并检查操作(Token机制 或 GUID) <strong>，一般不建议使用</strong></li></ol><h2 id="消息积压处理" tabindex="-1"><a class="header-anchor" href="#消息积压处理" aria-hidden="true">#</a> <strong>消息积压处理</strong></h2><h3 id="优化性能" tabindex="-1"><a class="header-anchor" href="#优化性能" aria-hidden="true">#</a> <strong>优化性能</strong></h3><p>发送端：增加批量(提高吞吐量)、提高并发(降低时延)<br> 消费端：</p><ol><li>系统设计时，保证消费性能高于生产端发送性能</li><li><strong>水平扩容</strong>，增加consumer实例，并与 <strong>队列/分区(Partition)</strong> 数量保持一致</li></ol><h3 id="问题排查" tabindex="-1"><a class="header-anchor" href="#问题排查" aria-hidden="true">#</a> <strong>问题排查</strong></h3><p>问题：排查是否是<strong>消费失败(如消息格式异常)导致的一条消息反复消费</strong>的情况 ?<br> 解决方案：消息队列中间件提供 “<strong>死信队列</strong>” 功能，自动把反复消费失败的消息丢到死信队列中，避免一条消息卡住队列。</p><h1 id="faq" tabindex="-1"><a class="header-anchor" href="#faq" aria-hidden="true">#</a> FAQ</h1><h2 id="_1、单个队列并行消费如何实现" tabindex="-1"><a class="header-anchor" href="#_1、单个队列并行消费如何实现" aria-hidden="true">#</a> 1、单个队列并行消费如何实现 ?</h2><p>此时，将 <strong>队列 : 消费者</strong> 置成 <strong>1 : N</strong> 即可。</p><p>问题：消息空洞(e.g. 3个消费者实例读1个队列(Queue)中的5、6、7三条消息，<strong>6、7 ACK</strong> 返回但 <strong>5 ACK</strong> 未返回)</p><p>解决方案：消息队列中间件提供 “<strong>重试队列</strong>” 功能，将5这条消息复制到重试队列，更新消费位置为8，继续消费。下次拉消息时，优先把重试队列中的消息给消费者。</p><h2 id="_2、如何保证消息的严格顺序" tabindex="-1"><a class="header-anchor" href="#_2、如何保证消息的严格顺序" aria-hidden="true">#</a> 2、如何保证消息的严格顺序 ？</h2><p><strong>全局严格顺序</strong>：将队列数置为1即可。<br><strong>局部严格顺序</strong>：通过一致性哈希算法指定队列发送消息实现。</p><h1 id="参考文献" tabindex="-1"><a class="header-anchor" href="#参考文献" aria-hidden="true">#</a> 参考文献</h1>',64),f={href:"http://juconcurrent.com/books-jksj-71-80/",target:"_blank",rel:"noopener noreferrer"},_={href:"https://cwiki.apache.org/confluence/display/KAFKA/Kafka+Improvement+Proposals",target:"_blank",rel:"noopener noreferrer"},x={href:"https://kafka.apache.org/documentation/#introduction",target:"_blank",rel:"noopener noreferrer"};function k(Q,P){const o=a("ExternalLinkIcon");return e(),l("div",null,[m,r("ol",null,[r("li",null,[r("a",f,[n("http://juconcurrent.com/books-jksj-71-80/"),t(o)])]),r("li",null,[r("a",_,[n("https://cwiki.apache.org/confluence/display/KAFKA/Kafka+Improvement+Proposals"),t(o)])]),r("li",null,[r("a",x,[n("https://kafka.apache.org/documentation/#introduction"),t(o)])])])])}const y=s(b,[["render",k],["__file","MQ.html.vue"]]);export{y as default};
